#include <stdio.h>
#include <limits.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int S[105];
        for(int i=0;i<N;i++) scanf("%d",&S[i]);
        char V[105]; scanf("%s",V);
        int ans = INT_MAX;
        for(int i=0;i<N;i++) if(V[i]=='0' && S[i]<ans) ans=S[i];
        printf("%d\n",ans);
    }
    return 0;
}

