const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const S = [];
  for (let i = 0; i < N; i++) S.push(Number(input[idx++]));
  const V = input[idx++];
  let ans = Infinity;
  for (let i = 0; i < N; i++) {
    if (V[i] === '0' && S[i] < ans) ans = S[i];
  }
  outputs.push(String(ans));
}
